// ❌ BAD - assuming setTimeout(fn, 0) fires before a promise
setTimeout(() => console.log('timer'), 0);
Promise.resolve().then(() => console.log('promise'));
// Mistake: developer thinks output is 'timer', 'promise'

// ✅ GOOD - understand the correct order
console.log('sync-start');
setTimeout(() => console.log('macrotask: timer'), 0);
Promise.resolve().then(() => console.log('microtask: promise'));
console.log('sync-end');
// Output: sync-start, sync-end, microtask: promise, macrotask: timer

// ❌ BAD - assuming 0ms timer fires before sync code
setTimeout(() => console.log('order confirmation sent'), 0);
console.log('checkout complete');
// Mistake: developer expects 'order confirmation sent' first

// ✅ GOOD - sync always runs before macrotask callbacks
console.log('checkout complete');    // runs first
setTimeout(() => {
  console.log('order confirmation sent'); // runs after sync
}, 0);
// Output: checkout complete, order confirmation sent

// ❌ BAD - callback hell for sequential API calls
getUser(userId, (user) => {
  getOrders(user.id, (orders) => {
    getInvoice(orders[0].id, (invoice) => { /* deeply nested */ });
  });
});

// ✅ GOOD - async/await for clean sequential flow
async function loadUserDashboard(userId) {
  const user = await getUser(userId);
  const orders = await getOrders(user.id);
  const invoice = await getInvoice(orders[0].id);
  return { user, orders, invoice };
}

// ❌ BAD - heavy sync work blocks the UI thread
function processLargeReport(rows) {
  return rows.map(row => heavyTransform(row)); // freezes browser
}

// ✅ GOOD - offload to a Web Worker to keep UI responsive
const reportWorker = new Worker('report-worker.js');
reportWorker.postMessage({ rows });
reportWorker.onmessage = (e) => renderResults(e.data);

// ❌ BAD - parsing a large product catalogue on the main thread
function buildSearchIndex(products) {
  return products.map(p => tokenize(p.description)); // blocks UI
}

// ✅ GOOD - offload to a Web Worker
const searchWorker = new Worker('search-index-worker.js');
searchWorker.postMessage({ products });
searchWorker.onmessage = (e) => {
  searchIndex = e.data.index; // main thread receives result
  enableSearchBar();
};

// ❌ BAD - dropping the order when offline instead of queuing it
async function submitOrder(order) {
  if (!navigator.onLine) { alert('No internet'); return; } // data lost
  await fetch('/api/orders', { method: 'POST', body: JSON.stringify(order) });
}

// ✅ GOOD - queue offline and sync when back online
async function submitOrder(order) {
  if (!navigator.onLine) {
    await saveToIndexedDB('pendingOrders', order);
    return showBanner('Order saved - will send when back online');
  }
  await fetch('/api/orders', { method: 'POST', body: JSON.stringify(order) });
}

// ❌ BAD - no chaining, verbose intermediate variables
const filtered = orders.filter(o => o.status === 'shipped');
const totals = filtered.map(o => o.total);
const revenue = totals.reduce((acc, v) => acc + v, 0);

// ✅ GOOD - method chaining for a clean pipeline
const shippedRevenue = orders
  .filter(o => o.status === 'shipped')
  .map(o => o.total)
  .reduce((acc, v) => acc + v, 0);

// ❌ BAD - assuming timer fires before promise because it was registered first
setTimeout(() => console.log('payment processed'), 0);
Promise.resolve().then(() => console.log('cart cleared'));
// Wrong assumption: 'payment processed' then 'cart cleared'

// ✅ GOOD - know the correct order
console.log('checkout started');                            // 1: sync
setTimeout(() => console.log('analytics sent'), 0);        // 4: macrotask
Promise.resolve().then(() => console.log('cart cleared')); // 3: microtask
console.log('checkout ended');                             // 2: sync
// Output: checkout started, checkout ended, cart cleared, analytics sent
